// Hardware atomic instruction
boolean TestAndSet(boolean *target) {
 boolean temp = *target;
 *target = TRUE;
 return temp;
}

// Lock implementation using Test-and-Set
do {
 while (TestAndSet(&lock)); // Spin until lock acquired
 critical_section();
 lock = FALSE; // Release lock
 remainder_section();
} while (TRUE);

// Semaphore structure
struct semaphore {
 int value; // Count of available resources
 queue processQueue; // Queue of blocked processes
};

// Wait (P) operation
wait(semaphore *S) {
 S->value--;
 if (S->value < 0) {
 // Block this process
 add_to_queue(S->processQueue, current_process);
 block(); // Move process to blocked state
 }
}

// Signal (V) operation
signal(semaphore *S) {
 S->value++;
 if (S->value <= 0) {
 // Wake up one waiting process
 remove_from_queue(S->processQueue, some_process);
 wakeup(some_process); // Move to ready queue
 }
}

// Shared variables
int turn; // Whose turn
boolean flag[2]; // Interest in entering CS

// Process i (where i is 0 or 1, j is the other)
do {
 flag[i] = TRUE; // Indicate desire to enter
 turn = j; // Give priority to other
 while (flag[j] && turn == j); // Wait while other wants and it's their turn

 critical_section(); // Protected code

 flag[i] = FALSE; // No longer interested

 remainder_section(); // Non-critical work
} while (TRUE);
